#include <cmath>
#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <omp.h>

#define fp float

#ifndef NUMBER_THREADS
#define NUMBER_THREADS 256
#endif

void extract_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = exp(d_I[ei] / 255);
    }
}

void prepare_kernel(long d_Ne, fp* d_I, fp* d_sums, fp* d_sums2) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

void reduce_kernel(long d_Ne, long d_no, int d_mul, fp* d_sums, fp* d_sums2, int gridDim) {
    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < gridDim; bx++) {
        fp d_psum[NUMBER_THREADS];
        fp d_psum2[NUMBER_THREADS];

        int nf = NUMBER_THREADS - (gridDim * NUMBER_THREADS - d_no);
        int df = 0;

        for (int tx = 0; tx < NUMBER_THREADS; tx++) {
            int ei = bx * NUMBER_THREADS + tx;
            if (d_no > ei) {
                d_psum[tx] = d_sums[ei * d_mul];
                d_psum2[tx] = d_sums2[ei * d_mul];
            } else {
                d_psum[tx] = 0.0f;
                d_psum2[tx] = 0.0f;
            }
        }

        if (nf == NUMBER_THREADS) {
            for (int i = 2; i <= NUMBER_THREADS; i *= 2) {
                for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                    if (((tx + 1) % i) == 0) {
                        d_psum[tx] += d_psum[tx - i / 2];
                        d_psum2[tx] += d_psum2[tx - i / 2];
                    }
                }
            }
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
        } else {
            if (bx != (gridDim - 1)) {
                for (int i = 2; i <= NUMBER_THREADS; i *= 2) {
                    for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                        if (((tx + 1) % i) == 0) {
                            d_psum[tx] += d_psum[tx - i / 2];
                            d_psum2[tx] += d_psum2[tx - i / 2];
                        }
                    }
                }
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
            } else {
                for (int i = 2; i <= NUMBER_THREADS; i *= 2) {
                    if (i <= nf) {
                        df = i;
                    }
                }
                for (int i = 2; i <= df; i *= 2) {
                    for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                        if (((tx + 1) % i) == 0 && df > tx) {
                            d_psum[tx] += d_psum[tx - i / 2];
                            d_psum2[tx] += d_psum2[tx - i / 2];
                        }
                    }
                }
                int tx = df - 1;
                if (tx >= 0 && tx < NUMBER_THREADS) {
                    for (int i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                        d_psum[tx] += d_sums[i];
                        d_psum2[tx] += d_sums2[i];
                    }
                    d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                    d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
                }
            }
        }
    }
}

void srad_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne,
                 int* d_iN, int* d_iS, int* d_jE, int* d_jW,
                 fp* d_dN, fp* d_dS, fp* d_dE, fp* d_dW,
                 fp d_q0sqr, fp* d_c, fp* d_I) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (int)((ei + 1) % d_Nr) - 1;
        int col = (int)((ei + 1) / d_Nr) + 1 - 1;
        if (((ei + 1) % d_Nr) == 0) {
            row = d_Nr - 1;
            col -= 1;
        }

        fp d_Jc = d_I[ei];
        fp d_dN_loc = d_I[d_iN[row] + d_Nr * col] - d_Jc;
        fp d_dS_loc = d_I[d_iS[row] + d_Nr * col] - d_Jc;
        fp d_dW_loc = d_I[row + d_Nr * d_jW[col]] - d_Jc;
        fp d_dE_loc = d_I[row + d_Nr * d_jE[col]] - d_Jc;

        fp d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);
        fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

        fp d_num = (0.5f * d_G2) - ((1.0f / 16.0f) * (d_L * d_L));
        fp d_den = 1.0f + (0.25f * d_L);
        fp d_qsqr = d_num / (d_den * d_den);

        d_den = (d_qsqr - d_q0sqr) / (d_q0sqr * (1.0f + d_q0sqr));
        fp d_c_loc = 1.0f / (1.0f + d_den);

        if (d_c_loc < 0.0f) d_c_loc = 0.0f;
        else if (d_c_loc > 1.0f) d_c_loc = 1.0f;

        d_dN[ei] = d_dN_loc;
        d_dS[ei] = d_dS_loc;
        d_dW[ei] = d_dW_loc;
        d_dE[ei] = d_dE_loc;
        d_c[ei] = d_c_loc;
    }
}

void srad2_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne,
                  int* d_iN, int* d_iS, int* d_jE, int* d_jW,
                  fp* d_dN, fp* d_dS, fp* d_dE, fp* d_dW,
                  fp* d_c, fp* d_I) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (int)((ei + 1) % d_Nr) - 1;
        int col = (int)((ei + 1) / d_Nr) + 1 - 1;
        if (((ei + 1) % d_Nr) == 0) {
            row = d_Nr - 1;
            col -= 1;
        }

        fp d_cN = d_c[ei];
        fp d_cS = d_c[d_iS[row] + d_Nr * col];
        fp d_cW = d_c[ei];
        fp d_cE = d_c[row + d_Nr * d_jE[col]];

        fp d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];

        d_I[ei] = d_I[ei] + 0.25f * d_lambda * d_D;
    }
}

void compress_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = log(d_I[ei]) * 255;
    }
}

// Implementation of kernel_gpu_opencl_wrapper function
void kernel_gpu_opencl_wrapper(fp* image, int Nr, int Nc, long Ne, int niter, fp lambda, long NeROI,
                               int* iN, int* iS, int* jE, int* jW, int iter, int mem_size_i, int mem_size_j) {
    // Allocate arrays for device buffers simulation
    fp* d_I = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums2 = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dN = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dS = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dW = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dE = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_c = (fp*)malloc(sizeof(fp) * Ne);

    int gridDim = (Ne + NUMBER_THREADS - 1) / NUMBER_THREADS;

    // Copy image to d_I
    memcpy(d_I, image, sizeof(fp) * Ne);

    // Extract kernel
    extract_kernel(Ne, d_I);

    for (iter = 0; iter < niter; iter++) {
        // Prepare kernel
        prepare_kernel(Ne, d_I, d_sums, d_sums2);

        // Reduction kernel loop
        long no = Ne;
        int mul = 1;
        int blocks2_work_size = gridDim;
        while (blocks2_work_size > 0) {
            reduce_kernel(Ne, no, mul, d_sums, d_sums2, blocks2_work_size);

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            } else {
                mul *= NUMBER_THREADS;
                blocks2_work_size = (blocks2_work_size + NUMBER_THREADS - 1) / NUMBER_THREADS;
            }
        }

        // Compute meanROI, meanROI2, varROI, q0sqr
        fp total = d_sums[0];
        fp total2 = d_sums2[0];
        fp meanROI = total / (fp)(NeROI);
        fp meanROI2 = meanROI * meanROI;
        fp varROI = (total2 / (fp)(NeROI)) - meanROI2;
        fp q0sqr = varROI / meanROI2;

        // SRAD kernel
        srad_kernel(lambda, Nr, Nc, Ne, iN, iS, jE, jW, d_dN, d_dS, d_dE, d_dW, q0sqr, d_c, d_I);

        // SRAD2 kernel
        srad2_kernel(lambda, Nr, Nc, Ne, iN, iS, jE, jW, d_dN, d_dS, d_dE, d_dW, d_c, d_I);
    }

    // Compress kernel
    compress_kernel(Ne, d_I);

    // Copy back to image
    memcpy(image, d_I, sizeof(fp) * Ne);

    // Free allocated memory
    free(d_I);
    free(d_sums);
    free(d_sums2);
    free(d_dN);
    free(d_dS);
    free(d_dW);
    free(d_dE);
    free(d_c);
}

